code = """import json
import re

# Load data
data = locals()['var_function-call-14653229810486529911']
if isinstance(data, str):
    with open(data, 'r') as f:
        data = json.load(f)

# Markers indicating start of categories
markers = [
    "including ",
    "services in ",
    "categories of ",
    "category of ",
    "categories such as ",
    "specializes in ",
    "destination for ",
    "selection of ",
    "ranging from ",
    "featuring ",
    "fields of ",
    "array of "
]

# Markers indicating end of categories (noise)
end_markers = [
    " to meet ",
    " making it ",
    " along with ",
    " for all your ",
    " for every ",
    " offering ", # sometimes "..., offering a range of..."
]

category_counts = {}
category_businesses = {}

for entry in data:
    desc = entry.get('description', '')
    bid = entry.get('business_id')
    
    # 1. Find start
    start_index = -1
    best_marker_len = 0
    
    for m in markers:
        idx = desc.rfind(m)
        if idx != -1:
            if idx > start_index:
                start_index = idx
                best_marker_len = len(m)
            elif idx == start_index:
                if len(m) > best_marker_len:
                    best_marker_len = len(m)
    
    if start_index != -1:
        cats_str = desc[start_index + best_marker_len:]
        
        # 2. Find end
        end_index = len(cats_str)
        for em in end_markers:
            e_idx = cats_str.find(em)
            if e_idx != -1 and e_idx < end_index:
                end_index = e_idx
        
        cats_str = cats_str[:end_index]
        
        # 3. Clean
        cats_str = cats_str.strip().strip('.').strip()
        
        # 4. Split
        # handle "ranging from X to Y" if " to " is present as a separator?
        # heuristic: if " to " is present and we used "ranging from", maybe it's a delimiter. 
        # But " to " is also handled by end_markers if it starts a phrase like " to meet".
        # If it's "ranging from A, B to C", then " to " is a separator before C?
        # Let's simple split by comma first.
        
        raw_cats = [c.strip() for c in cats_str.split(',')]
        
        final_cats = []
        for c in raw_cats:
            if not c: continue
            
            # Handle "and " prefix
            if c.lower().startswith('and '):
                c = c[4:].strip()
            
            # Handle "to " prefix (if "ranging from ... to ...")
            if c.lower().startswith('to '):
                c = c[3:].strip()
            
            # Handle embedded " and "
            if ' and ' in c:
                parts = c.split(' and ')
                final_cats.extend([p.strip() for p in parts])
            else:
                final_cats.append(c)
        
        # Add to counts
        for c in final_cats:
            # Clean up quotes if present (e.g. 'Restaurants, Chinese')
            c = c.replace("'", "")
            if not c: continue
            
            if c not in category_counts:
                category_counts[c] = 0
                category_businesses[c] = []
            
            # Avoid duplicate counting for same business
            if bid not in category_businesses[c]:
                category_counts[c] += 1
                category_businesses[c].append(bid)

# Find top category
if not category_counts:
    print("__RESULT__:")
    print(json.dumps({"error": "No categories found"}))
else:
    sorted_cats = sorted(category_counts.items(), key=lambda x: x[1], reverse=True)
    top_category = sorted_cats[0][0]
    top_count = sorted_cats[0][1]
    top_businesses = category_businesses[top_category]
    
    print("__RESULT__:")
    print(json.dumps({
        "top_category": top_category,
        "count": top_count,
        "business_ids": top_businesses
    }))"""

